//! Session persistence — JSON files in ~/.runie/sessions/

use crate::model::ChatMessage;
use serde::{Deserialize, Serialize};
use std::path::PathBuf;

/// Session snapshot — serializable conversation state
#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct Session {
    pub name: String,
    pub created_at: f64,
    pub updated_at: f64,
    pub messages: Vec<ChatMessage>,
    pub provider: String,
    pub model: String,
}

/// Session store — handles save/load/list/delete
#[derive(Debug, Clone)]
pub struct Store {
    pub dir: PathBuf,
}

impl Store {
    /// Default store — uses OS data dir (~/.local/share/runie/sessions on Linux)
    pub fn default() -> Option<Self> {
        dirs::data_dir().map(|d| Self::new(d.join("runie").join("sessions")))
    }

    /// Store with explicit directory (for testing)
    pub fn new(dir: PathBuf) -> Self {
        Self { dir }
    }

    pub fn path(&self, name: &str) -> PathBuf {
        self.dir.join(format!("{}.json", name))
    }

    fn ensure_dir(&self) -> std::io::Result<()> {
        std::fs::create_dir_all(&self.dir)
    }

    /// Save session to JSON file
    pub fn save(&self, name: &str, session: &Session) -> anyhow::Result<()> {
        self.ensure_dir()?;
        let json = serde_json::to_string_pretty(session)?;
        std::fs::write(self.path(name), json)?;
        Ok(())
    }

    /// Load session from JSON file
    pub fn load(&self, name: &str) -> anyhow::Result<Session> {
        let json = std::fs::read_to_string(self.path(name))?;
        let session: Session = serde_json::from_str(&json)?;
        Ok(session)
    }

    /// List all saved session names (sorted)
    pub fn list(&self) -> anyhow::Result<Vec<String>> {
        if !self.dir.exists() {
            return Ok(Vec::new());
        }
        let mut names = Vec::new();
        for entry in std::fs::read_dir(&self.dir)? {
            let entry = entry?;
            let name = entry.file_name().to_string_lossy().to_string();
            if let Some(stem) = name.strip_suffix(".json") {
                names.push(stem.to_string());
            }
        }
        names.sort();
        Ok(names)
    }

    /// Delete a session file
    pub fn delete(&self, name: &str) -> anyhow::Result<()> {
        std::fs::remove_file(self.path(name))?;
        Ok(())
    }
}



pub fn default_store() -> Option<Store> {
    if let Ok(dir) = std::env::var("RUNIE_SESSIONS_DIR") {
        return Some(Store::new(PathBuf::from(dir)));
    }
    Store::default()
}

pub fn save(name: &str, session: &Session) -> anyhow::Result<()> {
    default_store()
        .ok_or_else(|| anyhow::anyhow!("No data directory"))?
        .save(name, session)
}

pub fn load(name: &str) -> anyhow::Result<Session> {
    default_store()
        .ok_or_else(|| anyhow::anyhow!("No data directory"))?
        .load(name)
}

pub fn list() -> anyhow::Result<Vec<String>> {
    default_store()
        .ok_or_else(|| anyhow::anyhow!("No data directory"))?
        .list()
}

pub fn delete(name: &str) -> anyhow::Result<()> {
    default_store()
        .ok_or_else(|| anyhow::anyhow!("No data directory"))?
        .delete(name)
}





#[cfg(test)]
mod tests {
    use super::*;
    use crate::model::{ChatMessage, Role};
    use std::sync::atomic::{AtomicU64, Ordering};

    static COUNTER: AtomicU64 = AtomicU64::new(0);

    fn tmp_store() -> Store {
        let n = COUNTER.fetch_add(1, Ordering::SeqCst);
        let dir = std::env::temp_dir().join(format!("runie_test_{}_{}", std::process::id(), n));
        let _ = std::fs::remove_dir_all(&dir);
        Store::new(dir)
    }

    fn sample_session(name: &str) -> Session {
        Session {
            name: name.to_string(),
            created_at: 1.0,
            updated_at: 2.0,
            messages: vec![
                ChatMessage { role: Role::User, content: "hi".into(), timestamp: 1.0, id: "req.0".into() },
                ChatMessage { role: Role::Assistant, content: "hello".into(), timestamp: 2.0, id: "resp.0".into() },
            ],
            provider: "mock".into(),
            model: "echo".into(),
        }
    }

    #[test]
    fn save_creates_json_file() {
        let store = tmp_store();
        let session = sample_session("test1");
        store.save("test1", &session).unwrap();
        assert!(store.path("test1").exists(), "JSON file should exist");
    }

    #[test]
    fn load_roundtrip() {
        let store = tmp_store();
        let original = sample_session("roundtrip");
        store.save("roundtrip", &original).unwrap();
        let loaded = store.load("roundtrip").unwrap();
        assert_eq!(loaded.name, "roundtrip");
        assert_eq!(loaded.messages.len(), 2);
        assert_eq!(loaded.messages[0].role, Role::User);
        assert_eq!(loaded.messages[0].content, "hi");
        assert_eq!(loaded.provider, "mock");
        assert_eq!(loaded.model, "echo");
    }

    #[test]
    fn list_returns_sorted_names() {
        let store = tmp_store();
        store.save("beta", &sample_session("beta")).unwrap();
        store.save("alpha", &sample_session("alpha")).unwrap();
        store.save("gamma", &sample_session("gamma")).unwrap();
        let names = store.list().unwrap();
        assert_eq!(names, vec!["alpha", "beta", "gamma"]);
    }

    #[test]
    fn list_empty_dir_returns_empty() {
        let store = tmp_store();
        let names = store.list().unwrap();
        assert!(names.is_empty());
    }

    #[test]
    fn load_missing_session_fails() {
        let store = tmp_store();
        let result = store.load("nonexistent");
        assert!(result.is_err());
    }

    #[test]
    fn delete_removes_session() {
        let store = tmp_store();
        store.save("to_delete", &sample_session("to_delete")).unwrap();
        assert!(store.path("to_delete").exists());
        store.delete("to_delete").unwrap();
        assert!(!store.path("to_delete").exists());
    }

    #[test]
    fn serialize_role_roundtrip() {
        let role = Role::Assistant;
        let json = serde_json::to_string(&role).unwrap();
        let decoded: Role = serde_json::from_str(&json).unwrap();
        assert_eq!(role, decoded);
    }

    #[test]
    fn serialize_chat_message_roundtrip() {
        let msg = ChatMessage { role: Role::User, content: "test".into(), timestamp: 1.5, id: "req.1".into() };
        let json = serde_json::to_string(&msg).unwrap();
        let decoded: ChatMessage = serde_json::from_str(&json).unwrap();
        assert_eq!(msg.role, decoded.role);
        assert_eq!(msg.content, decoded.content);
        assert_eq!(msg.timestamp, decoded.timestamp);
        assert_eq!(msg.id, decoded.id);
    }

    #[test]
    fn serialize_session_full_roundtrip() {
        let session = sample_session("full");
        let json = serde_json::to_string_pretty(&session).unwrap();
        let decoded: Session = serde_json::from_str(&json).unwrap();
        assert_eq!(session.name, decoded.name);
        assert_eq!(session.messages.len(), decoded.messages.len());
    }
}

//! Provider trait and message types

use anyhow::Result;

/// Message roles for LLM conversations
#[derive(Debug, Clone, PartialEq)]
pub enum Message {
    System { content: String },
    User { content: String },
    Assistant { content: String },
    ToolResult { content: String },
}

impl Message {
    pub fn role(&self) -> &'static str {
        match self {
            Message::System { .. } => "system",
            Message::User { .. } => "user",
            Message::Assistant { .. } => "assistant",
            Message::ToolResult { .. } => "tool",
        }
    }

    pub fn content(&self) -> &str {
        match self {
            Message::System { content }
            | Message::User { content }
            | Message::Assistant { content }
            | Message::ToolResult { content } => content,
        }
    }
}

/// A chunk of streaming response
#[derive(Debug, Clone)]
pub struct ResponseChunk {
    pub content: String,
}

/// Provider trait — implemented by LLM backends.
/// Streams chunks via the `on_chunk` callback as they arrive from the API.
pub trait Provider: Send + Sync {
    #[allow(async_fn_in_trait)]
    async fn generate<F>(&self, messages: Vec<Message>, on_chunk: F) -> Result<()>
    where
        F: FnMut(ResponseChunk) + Send;
}

//! Runie Provider - Concrete LLM provider implementations

pub mod mock;
pub mod model;
pub mod openai;
pub mod config;

pub use mock::MockProvider;
pub use model::{ModelId, ModelRegistry};
pub use openai::OpenAiProvider;
pub use config::Config;

use anyhow::Result;
use runie_core::provider::{Message, Provider, ResponseChunk};

/// Runtime provider selection — closed enum for static dispatch.
pub enum AnyProvider {
    Mock(MockProvider),
    OpenAi(OpenAiProvider),
}

impl AnyProvider {
    fn build(provider: &str, model: &str) -> Self {
        let config = Config::load();
        Self::build_with_config(provider, model, &config)
    }

    fn build_with_config(provider: &str, model: &str, config: &Config) -> Self {
        if let Some(custom) = config.model_providers.get(provider) {
            return Self::OpenAi(OpenAiProvider::new(
                custom.api_key.clone(),
                model,
            ).with_base_url(custom.base_url.clone()));
        }
        match provider {
            "openai" => {
                let key = std::env::var("OPENAI_API_KEY").unwrap_or_default();
                if key.is_empty() {
                    eprintln!("Warning: OPENAI_API_KEY not set, falling back to mock");
                    Self::Mock(MockProvider::default())
                } else {
                    Self::OpenAi(OpenAiProvider::new(key, model))
                }
            }
            _ => {
                if std::env::var("RUNIE_MOCK_DELAY").is_ok() {
                    Self::Mock(MockProvider::with_delay(500, 3000))
                } else {
                    Self::Mock(MockProvider::default())
                }
            }
        }
    }

    pub fn new(provider: &str, model: &str) -> Self {
        Self::build(provider, model)
    }

    pub fn from_env() -> Self {
        let config = Config::load();
        Self::from_config(&config, config.default_model().unwrap_or("echo"))
    }

    pub fn from_config(config: &Config, model: &str) -> Self {
        let provider = if model.contains('/') {
            model.split('/').next().unwrap_or("mock")
        } else {
            config.provider.as_deref().unwrap_or("mock")
        };
        Self::build_with_config(provider, model, config)
    }

    pub fn switch(&mut self, provider: &str, model: &str) {
        *self = Self::build(provider, model);
    }

    pub fn name(&self) -> &'static str {
        match self {
            AnyProvider::Mock(_) => "mock",
            AnyProvider::OpenAi(_) => "openai",
        }
    }

    pub fn model(&self) -> String {
        match self {
            AnyProvider::Mock(_) => "echo".to_string(),
            AnyProvider::OpenAi(p) => p.model().to_string(),
        }
    }
}

impl Provider for AnyProvider {
    async fn generate<F>(&self, messages: Vec<Message>, on_chunk: F) -> Result<()>
    where
        F: FnMut(ResponseChunk) + Send,
    {
        match self {
            AnyProvider::Mock(p) => p.generate(messages, on_chunk).await,
            AnyProvider::OpenAi(p) => p.generate(messages, on_chunk).await,
        }
    }
}

